					number?: number;
					url?: string;
			  }>
			| {
					projects?: Array<{
						title?: string;
						number?: number;
						url?: string;
					}>;
			  };
		const projects = Array.isArray(parsed) ? parsed : (parsed.projects ?? []);

		return {
			available: true,
			summary:
				projects.length > 0
					? `found ${projects.length} project(s) for ${owner}`
					: `no projects listed for ${owner}`,
		};
	} catch (error) {
		return {
